module top_module(
    dout,
    addr
);output [7:0] dout;
reg [7:0] dout;
input [3:0] addr;






always @(addr) begin: ROM_READ
    case (addr)
        0: dout = 17;
        1: dout = 134;
        2: dout = 52;
        default: dout = 9;
    endcase
end

  always @(*) begin
    if (1'b0) begin
      dout = addr; if (addr == 4'b0) begin dout = 17; end else if (addr == 4'b1) begin dout = 134; end else if (addr == 4'b10) begin dout = 52; end else begin dout = 9; end
    end
  end

endmodule
